// GitHub node returns file content as base64 in $json.content
const decode = (b64) => Buffer.from(b64.replace(/\n/g, ''), 'base64').toString('utf8');

const diagramTypesRaw = decode($('Fetch: Diagram Types Dataset').first().json.content);
const promptTemplate = decode($('Fetch: Prompt Template').first().json.content);
const visualStylesRaw = decode($('Fetch: Visual Styles Dataset').first().json.content);
const colorPresetsRaw = decode($('Fetch: Color Presets Dataset').first().json.content);
const config = $('Init: Set GitHub Config').first().json;

const diagramTypes = JSON.parse(diagramTypesRaw);
const visualStyles = JSON.parse(visualStylesRaw);
const colorPresets = JSON.parse(colorPresetsRaw);

return [{
  diagramTypes,
  visualStyles,
  colorPresets,
  promptTemplate,
  diagramDescription: config.diagramDescription,
  githubOwner: config.githubOwner,
  githubRepo: config.githubRepo,
  githubBranch: config.githubBranch
}];

const selection = $input.first().json;
const parsedData = $('Parse: Dataset & Template').first().json;

// Extract diagram type id from the dropdown selection (format: "emoji id — Name")
const diagramTypeRaw = selection['Diagram Type'] || '';
const diagramTypeId = diagramTypeRaw.replace(/^\S+\s+/, '').split(' — ')[0].trim();

// Find the full diagram type object
const diagramType = parsedData.diagramTypes.find(d => d.id === diagramTypeId) || {};

const model = selection['Image Generation Model'] || '@openai-aifoundry-swc-001/gpt-image-1';
const additionalContext = selection['Additional Context (optional)'] || 'None';
const description = parsedData.diagramDescription;

// Filter visual styles compatible with this diagram type
const compatibleStyles = parsedData.visualStyles.filter(
  s => s.compatible_types.includes(diagramTypeId)
);
// Fallback: if no compatible styles found, return all styles
const visualStyles = compatibleStyles.length > 0 ? compatibleStyles : parsedData.visualStyles;

return [{
  diagramTypeId,
  diagramTypeName: diagramType.name || diagramTypeId,
  diagramTypeDescription: diagramType.description || '',
  styleHint: diagramType.style_hint || '',
  colorPalette: diagramType.color_palette || 'White background',
  diagramDescription: description,
  promptTemplate: parsedData.promptTemplate,
  model,
  additionalContext,
  visualStyles,
  colorPresets: parsedData.colorPresets
}];

