const styleSelection = $input.first().json;
const buildData = $('Build: Diagram Prompt').first().json;

// Extract visual style id from selection (format: "emoji id — Name")
const visualStyleRaw = styleSelection['Visual Style'] || '';
const visualStyleId = visualStyleRaw.replace(/^\S+\s+/, '').split(' — ')[0].trim();
const visualStyleObj = buildData.visualStyles.find(s => s.id === visualStyleId) || {};
const visualStyleName = visualStyleObj.name || visualStyleId;
const visualStyleDescription = visualStyleObj.description || '';

// Extract color preset id from selection (format: "emoji id — Name")
const colorPresetRaw = styleSelection['Color Preset'] || '';
const colorPresetId = colorPresetRaw.replace(/^\S+\s+/, '').split(' — ')[0].trim();
const colorPresetObj = buildData.colorPresets.find(c => c.id === colorPresetId) || {};
const colorPresetName = colorPresetObj.name || colorPresetId;
const colorPresetDescription = colorPresetObj.description || '';

// Substitute all placeholders — prompt is fully agnostic, all content comes from the datasets
let prompt = buildData.promptTemplate;
prompt = prompt.replace(/\{\{DIAGRAM_TYPE\}\}/g, buildData.diagramTypeName);
prompt = prompt.replace(/\{\{DIAGRAM_TYPE_DESCRIPTION\}\}/g, buildData.diagramTypeDescription + ' ' + buildData.styleHint);
prompt = prompt.replace(/\{\{DIAGRAM_TOPIC\}\}/g, buildData.diagramDescription);
prompt = prompt.replace(/\{\{VISUAL_STYLE\}\}/g, visualStyleName);
prompt = prompt.replace(/\{\{VISUAL_STYLE_DESCRIPTION\}\}/g, visualStyleDescription);
prompt = prompt.replace(/\{\{COLOR_PRESET\}\}/g, colorPresetName + ': ' + colorPresetDescription);
prompt = prompt.replace(/\{\{DIAGRAM_CONTEXT\}\}/g, buildData.additionalContext);

// Build a concise suggested image prompt (pre-filled in the edit form)
const suggestedImagePrompt = `"${buildData.diagramTypeName} diagram of ${buildData.diagramDescription}. Show at most 4-6 key elements. If flow matters, use A -> B -> C. Style: ${visualStyleName}. Palette: ${colorPresetName}. Clean vector lines, short labels."`;

return [{
  diagramTypeId: buildData.diagramTypeId,
  diagramTypeName: buildData.diagramTypeName,
  diagramDescription: buildData.diagramDescription,
  visualStyleId,
  visualStyleName,
  colorPresetId,
  colorPresetName,
  model: buildData.model,
  additionalContext: buildData.additionalContext,
  generatedSystemPrompt: prompt,
  suggestedImagePrompt
}];

