const response = $input.first().json;
const params = $('Set: Generation Params').first().json;

const choice = response.choices && response.choices[0];
if (!choice || !choice.message) {
  throw new Error('No response from OpenRouter. Response: ' + JSON.stringify(response));
}

const msg = choice.message;
const imageEntry = msg.images && msg.images[0];
if (!imageEntry || !imageEntry.image_url || !imageEntry.image_url.url) {
  throw new Error('No image in OpenRouter response. Message: ' + JSON.stringify(msg));
}

const dataUrl = imageEntry.image_url.url;
const image = dataUrl.includes(',') ? dataUrl.split(',')[1] : dataUrl;

const fileId = $execution.id + "_" + (Math.random() + 1).toString(36).substring(6);
const revisedPrompt = params.finalPrompt;

return [{
  image,
  fileId,
  revisedPrompt,
  originalPrompt: params.finalPrompt,
  model: params.model,
  diagramTypeName: params.diagramTypeName,
  visualStyleName: params.visualStyleName,
  imageSize: params.imageSize,
  generatedAt: new Date().toISOString()
}];

